import React, { useState } from "react";
import api from "../services/api"; // your existing axios instance
import { useNavigate } from "react-router-dom";
import {
  Box,
  Button,
  CircularProgress,
  Paper,
  TextField,
  Typography,
  Alert,
} from "@mui/material";

export default function Register() {
  const [form, setForm] = useState({ name: "", phone: "", email: "" });
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState({ type: "", text: "" });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setForm((s) => ({ ...s, [e.target.name]: e.target.value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    setMsg({ type: "", text: "" });

    // basic client-side validation
    if (!form.name.trim() || !form.phone.trim() || !form.email.trim()) {
      setMsg({ type: "error", text: "Please fill all required fields." });
      return;
    }

    try {
      setLoading(true);
      await api.post("/users/register", form); // uses your existing baseURL/interceptors
      setMsg({ type: "success", text: "Registered successfully! Redirecting to login..." });
      setTimeout(() => navigate("/login"), 1000);
    } catch (err) {
      const serverMsg = err?.response?.data?.message || err.message || "Registration failed";
      setMsg({ type: "error", text: serverMsg });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      display="flex"
      justifyContent="center"
      alignItems="center"
      minHeight="80vh"
      sx={{ bgcolor: "#f6f6f6", p: 2 }}
    >
      <Paper elevation={3} sx={{ p: 4, maxWidth: 520, width: "100%" }}>
        <Typography variant="h5" align="center" gutterBottom>
          Register
        </Typography>

        <Box component="form" onSubmit={submit} noValidate>
          <TextField
            label="Full Name"
            name="name"
            value={form.name}
            onChange={handleChange}
            fullWidth
            margin="normal"
            required
            autoComplete="name"
          />

          <TextField
            label="Phone"
            name="phone"
            value={form.phone}
            onChange={handleChange}
            fullWidth
            margin="normal"
            required
            autoComplete="tel"
          />

          <TextField
            label="Email"
            name="email"
            value={form.email}
            onChange={handleChange}
            fullWidth
            margin="normal"
            type="email"
            required
            autoComplete="email"
          />

          <Box mt={3} position="relative">
            <Button type="submit" variant="contained" fullWidth disabled={loading}>
              {loading ? "Registering..." : "Register"}
            </Button>

            {loading && (
              <CircularProgress
                size={24}
                sx={{
                  position: "absolute",
                  top: "50%",
                  left: "50%",
                  mt: "-12px",
                  ml: "-12px",
                }}
              />
            )}
          </Box>
        </Box>

        {msg.text && (
          <Box mt={2}>
            <Alert severity={msg.type === "success" ? "success" : "error"}>
              {msg.text}
            </Alert>
          </Box>
        )}
      </Paper>
    </Box>
  );
}
